/* --------------------------------------------------------------------------
   FAQAccordion
   -------------------------------------------------------------------------- */
function FAQAccordion({ faqs }) {
  const cats = useMemo(() => ["ALL", ...Array.from(new Set(faqs.map((f) => f.category)))], [faqs]);
  const [cat, setCat] = useState("ALL");
  const [q, setQ] = useState("");
  const [open, setOpen] = useState(-1);
  const shortCat = (c) => c.replace(/\s*[—/].*$/, "").replace(/\s*\(.*?\)\s*/g, "").trim();
  const filtered = faqs.filter((f) => {
    const inCat = cat === "ALL" || f.category === cat;
    const s = q.trim().toLowerCase();
    return inCat && (!s || f.q.toLowerCase().includes(s) || f.a.toLowerCase().includes(s));
  });
  return (
    <div className="fp-faq">
      <div className="fp-faq__search">
        <Icon name="search" />
        <input value={q} onChange={(e) => { setQ(e.target.value); setOpen(-1); }} placeholder="Search all questions…" />
        {q && <button onClick={() => setQ("")} aria-label="Clear"><Icon name="x" /></button>}
      </div>
      <div className="fp-faq__tabs">
        {cats.map((c) => <button key={c} className={"fp-faq__tab" + (cat === c ? " is-on" : "")} onClick={() => { setCat(c); setOpen(-1); }}>{c === "ALL" ? "ALL" : shortCat(c)}</button>)}
      </div>
      <div className="fp-faq__list">
        {filtered.length === 0 && <p className="fp-faq__empty">No questions match &ldquo;{q}&rdquo;.</p>}
        {filtered.map((f, i) => (
          <div key={i} className={"fp-faq__item" + (open === i ? " is-open" : "")}>
            <button className="fp-faq__q" onClick={() => setOpen(open === i ? -1 : i)}><span>{f.q}</span><Icon name={open === i ? "minus" : "plus"} /></button>
            {open === i && <div className="fp-faq__a"><span className="fp-faq__cat">{shortCat(f.category)}</span><p><RichText text={f.a} /></p></div>}
          </div>
        ))}
      </div>
    </div>
  );
}

