const findH3 = (blocks, re) => {
  const out = []; let on = false;
  for (const b of blocks || []) {
    if (b.type === "h3") { on = re.test(b.text); continue; }
    if (on) out.push(b);
  }
  return out;
};
const SubHead = ({ title }) => <h3 className="fp-subhead">{title}</h3>;

/* storage hook */
function useStored(key, initial) {
  const [val, setVal] = useState(null);
  const [ready, setReady] = useState(false);
  useEffect(() => {
    let live = true;
    (async () => {
      try { const r = await window.storage.get(key, false); if (live) setVal(r && r.value ? JSON.parse(r.value) : initial); }
      catch (e) { if (live) setVal(initial); }
      finally { if (live) setReady(true); }
    })();
    return () => { live = false; };
  }, [key]);
  const save = useCallback(async (next) => {
    setVal(next);
    try { await window.storage.set(key, JSON.stringify(next), false); } catch (e) { /* local only */ }
  }, [key]);
  return [val, save, ready];
}

