/* OnboardingQuiz (S00) — 4 questions, routes to split + program, persisted */
const QUIZ_Q = [
  { key: "age", q: "Training age", opts: [["New", "New (0–12 mo)"], ["Intermediate", "Intermediate (1–4 yr)"], ["Advanced", "Advanced (4+ yr)"]] },
  { key: "days", q: "Days per week available", opts: [["3", "3"], ["4", "4"], ["5", "5"], ["6", "6"]] },
  { key: "goal", q: "Primary goal", opts: [["Build", "Build Muscle"], ["Lean", "Get Leaner"], ["Both", "Both"]] },
  { key: "equip", q: "Equipment access", opts: [["Full", "Full Gym"], ["DB", "Dumbbells + Pull-up Bar"], ["Min", "Minimal / Bodyweight"]] },
];
function routeQuiz(a) {
  if (!a || !a.days) return null;
  let split, program;
  const d = a.days;
  if (a.equip === "Min") { split = "Home / Limited Equipment"; program = "Program 5 — Home/Limited Equipment Full-Body 3x"; }
  else if (d === "3") { split = "Full Body 3x"; program = a.age === "New" ? "Program 1 — Beginner Full-Body 3x" : "Program 1 — Beginner Full-Body 3x (add volume)"; }
  else if (d === "4") { split = "Upper / Lower 4x"; program = "Program 2 — Intermediate Upper/Lower 4x"; }
  else if (d === "5") { split = "5-Day Body Part"; program = "Program 4 — Advanced 5-Day Body Part Split"; }
  else { split = "Push / Pull / Legs 6x"; program = "Program 3 — Intermediate PPL 6x"; }
  return { split, program };
}
function OnboardingQuiz({ answers, save }) {
  const a = answers || {};
  const route = routeQuiz(a);
  const set = (k, v) => save({ ...a, [k]: v });
  return (
    <div className="tp-quiz">
      <div className="tp-quiz__lbl">FIND YOUR SPLIT — 4 QUESTIONS, SAVED TO YOUR SIDEBAR</div>
      {QUIZ_Q.map((qq) => (
        <div key={qq.key} className="tp-quiz__q">
          <div className="tp-quiz__qt">{qq.q}</div>
          <div className="tp-quiz__opts">
            {qq.opts.map(([val, lbl]) => (
              <button key={val} className={"tp-quiz__opt" + (a[qq.key] === val ? " is-active" : "")} onClick={() => set(qq.key, val)}>{lbl}</button>
            ))}
          </div>
        </div>
      ))}
      {route && (
        <div className="tp-quiz__result">
          <div className="tp-quiz__rh">YOUR MATCH</div>
          <div className="tp-quiz__rrow"><span className="tp-quiz__rk">Recommended split</span><span className="tp-quiz__rv">{route.split}</span></div>
          <div className="tp-quiz__rrow"><span className="tp-quiz__rk">Starting program</span><span className="tp-quiz__rv">{route.program}</span></div>
          <button className="tp-quiz__reset" onClick={() => save({})}><Icon name="reset" /> RESET</button>
        </div>
      )}
    </div>
  );
}

