/* EffectiveRepVisual (S02, S07) — draggable indicator on the effort spectrum */
function EffectiveRepVisual() {
  const [pos, setPos] = useState(58);
  const trackRef = useRef(null);
  const dragging = useRef(false);
  const setFromClientX = (clientX) => {
    const el = trackRef.current; if (!el) return;
    const r = el.getBoundingClientRect();
    setPos(Math.min(100, Math.max(0, ((clientX - r.left) / r.width) * 100)));
  };
  useEffect(() => {
    const move = (e) => { if (dragging.current) setFromClientX(e.touches ? e.touches[0].clientX : e.clientX); };
    const up = () => { dragging.current = false; };
    window.addEventListener("mousemove", move); window.addEventListener("mouseup", up);
    window.addEventListener("touchmove", move, { passive: false }); window.addEventListener("touchend", up);
    return () => { window.removeEventListener("mousemove", move); window.removeEventListener("mouseup", up); window.removeEventListener("touchmove", move); window.removeEventListener("touchend", up); };
  }, []);
  let read;
  if (pos < 30) read = { rir: "5+ RIR", t: "TOO EASY — real stimulus not yet reached. These reps are essentially a warm-up for the effective ones." };
  else if (pos < 80) read = { rir: "1–3 RIR", t: "OPTIMAL — effective reps are accumulating. This is the productive working zone for nearly every set." };
  else read = { rir: "0 RIR", t: "FAILURE ZONE — maximum stimulus per set but high fatigue cost. Use selectively, not as your default." };
  return (
    <div className="tp-spec">
      <div className="tp-spec__lbl">EFFECTIVE-REP SPECTRUM — DRAG TO SEE HOW EFFORT MAPS TO STIMULUS</div>
      <div className="tp-spec__track" ref={trackRef}
        onMouseDown={(e) => { dragging.current = true; setFromClientX(e.clientX); }}
        onTouchStart={(e) => { dragging.current = true; setFromClientX(e.touches[0].clientX); }}>
        <div className="tp-spec__zones">
          <div className="tp-spec__zone" style={{ flex: "0 0 30%" }}>TOO EASY</div>
          <div className="tp-spec__zone" style={{ flex: "0 0 50%" }}>OPTIMAL · 1–3 RIR</div>
          <div className="tp-spec__zone" style={{ flex: "0 0 20%" }}>FAILURE</div>
        </div>
        <div className="tp-spec__ind" style={{ left: pos + "%" }} />
      </div>
      <div className="tp-spec__scale"><span>0 — fresh</span><span>50</span><span>100 — failure</span></div>
      <div className="tp-spec__read"><div className="tp-spec__rv">{read.rir}</div><div className="tp-spec__rt">{read.t}</div></div>
    </div>
  );
}

/* VolumeTracker (S02) — recreates Image 2; logs hard sets vs MEV/MAV/MRV, persisted */
const VT_MUSCLES = ["Chest", "Back", "Shoulders", "Biceps", "Triceps", "Quads", "Hamstrings", "Glutes", "Calves", "Abs"];
const VT_TARGETS = {
  New:          { Chest:[6,10,14], Back:[8,12,16], Shoulders:[6,12,16], Biceps:[5,10,14], Triceps:[5,10,14], Quads:[6,10,16], Hamstrings:[5,9,13], Glutes:[4,8,12], Calves:[6,10,14], Abs:[4,8,12] },
  Intermediate: { Chest:[8,14,20], Back:[10,16,22], Shoulders:[8,16,22], Biceps:[6,14,20], Triceps:[6,12,18], Quads:[8,14,20], Hamstrings:[6,12,16], Glutes:[6,12,16], Calves:[8,14,18], Abs:[6,12,16] },
  Advanced:     { Chest:[10,16,22], Back:[12,18,25], Shoulders:[10,20,26], Biceps:[8,16,22], Triceps:[8,14,20], Quads:[10,18,22], Hamstrings:[8,14,18], Glutes:[8,14,18], Calves:[10,16,20], Abs:[8,14,18] },
};
function VolumeTracker() {
  const [data, save, ready] = useStored(K_VOL, { age: "Intermediate", cells: {} });
  if (!ready || !data) return <div className="fp-track fp-track--loading">Loading your volume tracker…</div>;
  const age = data.age || "Intermediate";
  const cells = data.cells || {};
  const toggle = (mi, di) => {
    const key = mi + "-" + di;
    const next = { ...cells, [key]: !cells[key] };
    save({ ...data, cells: next });
  };
  const setAge = (a) => save({ ...data, age: a });
  const weekTotal = (mi) => { let t = 0; for (let d = 0; d < 7; d++) if (cells[mi + "-" + d]) t++; return t; };
  return (
    <div className="tp-vt">
      <div className="tp-vt__lbl">WEEKLY VOLUME TRACKER — TAP A CELL PER HARD SET, vs YOUR MEV / MAV / MRV</div>
      <div className="tp-vt__age">
        {["New", "Intermediate", "Advanced"].map((a) => (
          <button key={a} className={"tp-tab" + (age === a ? " is-active" : "")} onClick={() => setAge(a)}>{a.toUpperCase()}</button>
        ))}
      </div>
      <div className="tp-vt__grid">
        <table className="tp-vt__table">
          <thead><tr><th className="tp-vt__mh"> </th>{[1,2,3,4,5,6,7].map((d) => <th key={d} className="tp-vt__dh">{d}</th>)}<th className="tp-vt__dh"> </th></tr></thead>
          <tbody>
            {VT_MUSCLES.map((mu, mi) => {
              const [mev, mav, mrv] = VT_TARGETS[age][mu];
              const tot = weekTotal(mi);
              let zone = "low", lbl = "below MEV";
              if (tot > mrv) { zone = "over"; lbl = "over MRV"; }
              else if (tot >= mav) { zone = "warn"; lbl = "→ MRV"; }
              else if (tot >= mev) { zone = "mav"; lbl = "in MAV"; }
              const pct = Math.min(100, (tot / mrv) * 100);
              return (
                <tr key={mu}>
                  <td className="tp-vt__mh">{mu}</td>
                  {[0,1,2,3,4,5,6].map((di) => (
                    <td key={di}><button className={"tp-vt__cell" + (cells[mi + "-" + di] ? " is-on" : "")} onClick={() => toggle(mi, di)} aria-label={mu + " day " + (di+1)} /></td>
                  ))}
                  <td className="tp-vt__stat">
                    <span style={{ color: "var(--accent-primary-bright)" }}>{tot}</span> / {mev}·{mav}·{mrv}
                    <div className="tp-vt__bar"><div className={"tp-vt__fill tp-vt__fill--" + zone} style={{ width: pct + "%" }} /></div>
                    <span className="tp-vt__zone" style={{ color: zone === "over" ? "var(--accent-red-text)" : zone === "warn" ? "var(--accent-warn-bright)" : zone === "mav" ? "var(--accent-primary-bright)" : "var(--text-muted)" }}>{lbl}</span>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
      <div className="tp-vt__row-foot">
        <button className="tp-vt__reset" onClick={() => save({ age, cells: {} })}><Icon name="reset" /> RESET WEEK</button>
        <span style={{ fontFamily: "var(--font-mono)", fontSize: 10, color: "var(--text-muted)" }}>Targets = MEV · MAV · MRV sets/week. Saved automatically.</span>
      </div>
    </div>
  );
}

