/* MesocyclePlanner (S11) — generates a week-by-week schedule, checkboxes persisted */
const MESO_MODELS = ["Linear", "DUP", "Block"];
function buildMeso(model, weeks) {
  const out = [];
  for (let w = 1; w <= weeks; w++) {
    const isDeload = w === weeks;
    let focus, vol, rir;
    if (isDeload) { focus = "Deload"; vol = "~50% volume"; rir = "3–4 RIR"; }
    else {
      const frac = (w - 1) / Math.max(1, weeks - 2);
      vol = frac < 0.34 ? "MEV → low MAV" : frac < 0.67 ? "MAV" : "MAV → MRV";
      rir = frac < 0.34 ? "3 RIR" : frac < 0.67 ? "2 RIR" : "1 RIR";
      focus = model === "Block" ? (frac < 0.5 ? "Accumulation" : "Intensification") : model === "DUP" ? "Undulating (vary daily)" : "Accumulation";
    }
    out.push({ w, focus, vol, rir, isDeload });
  }
  return out;
}
function MesocyclePlanner() {
  const [data, save, ready] = useStored(K_MESO, { model: "DUP", weeks: 5, done: {} });
  if (!ready || !data) return <div className="fp-track fp-track--loading">Loading planner…</div>;
  const weeks = buildMeso(data.model, data.weeks);
  const toggle = (w) => save({ ...data, done: { ...data.done, [w]: !data.done[w] } });
  return (
    <div className="tp-meso">
      <div className="tp-meso__lbl">MESOCYCLE PLANNER — AUTO-BUILDS YOUR WEEK-BY-WEEK SCHEME</div>
      <div className="tp-meso__ctrls">
        <div className="tp-meso__field">
          <span className="tp-meso__fl">Model</span>
          <div className="tp-seg">{MESO_MODELS.map((m) => <button key={m} className={"tp-seg__b" + (data.model === m ? " is-active" : "")} onClick={() => save({ ...data, model: m })}>{m.toUpperCase()}</button>)}</div>
        </div>
        <div className="tp-meso__field">
          <span className="tp-meso__fl">Length</span>
          <div className="tp-seg">{[4,5,6,8].map((n) => <button key={n} className={"tp-seg__b" + (data.weeks === n ? " is-active" : "")} onClick={() => save({ ...data, weeks: n, done: {} })}>{n}w</button>)}</div>
        </div>
      </div>
      {weeks.map((wk) => (
        <div key={wk.w} className={"tp-meso__week" + (wk.isDeload ? " is-deload" : "")}>
          <span className="tp-meso__wk">WEEK {wk.w}</span>
          <span className="tp-meso__wfocus">{wk.focus}</span>
          <span className="tp-meso__wmeta">{wk.vol} · {wk.rir}</span>
          <button className={"tp-meso__chk" + (data.done[wk.w] ? " is-on" : "")} onClick={() => toggle(wk.w)} aria-label={"week " + wk.w + " done"}>{data.done[wk.w] && <Icon name="check" />}</button>
        </div>
      ))}
    </div>
  );
}

