/* ProgramSelector (S18) — 5 programs as expandable cards, recommended by quiz */
function programMatchesQuiz(title, quiz) {
  if (!quiz || !quiz.days) return false;
  const t = title.toLowerCase();
  if (quiz.equip === "Min") return t.includes("home") || t.includes("limited");
  if (quiz.days === "3") return t.includes("beginner") || t.includes("full-body") || t.includes("full body");
  if (quiz.days === "4") return t.includes("upper/lower") || t.includes("upper / lower");
  if (quiz.days === "5") return t.includes("5-day") || t.includes("body part");
  if (quiz.days === "6") return t.includes("ppl") || t.includes("push/pull");
  return false;
}
function ProgramSelector({ groups, quiz }) {
  const [open, setOpen] = useState(null);
  return (
    <div>
      {groups.map((g, i) => {
        const rec = programMatchesQuiz(g.title, quiz);
        return (
          <div key={i} className={"tp-ps__card" + (rec ? " is-rec" : "")}>
            <div className="tp-ps__head" onClick={() => setOpen(open === i ? null : i)}>
              <Icon name="grid" />
              <span className="tp-ps__name">{g.title}</span>
              {rec && <span className="tp-ps__rec">RECOMMENDED FOR YOU</span>}
              <Icon name={open === i ? "minus" : "plus"} />
            </div>
            {open === i && <div className="tp-ps__body"><Blocks blocks={g.blocks} /></div>}
          </div>
        );
      })}
    </div>
  );
}

