/* CheatSheetPanel (S21) — accordions, interactive checklist, clipboard copy */
function blocksToText(blocks) {
  const out = [];
  for (const b of blocks || []) {
    if (b.type === "p" || b.type === "h3" || b.type === "h4") out.push(b.text.replace(/\*\*/g, ""));
    else if (b.type === "list") b.items.forEach((it) => out.push("- " + it.replace(/\*\*/g, "")));
    else if (b.type === "table") { out.push(b.header.join(" | ")); b.rows.forEach((r) => out.push(r.join(" | "))); }
  }
  return out.join("\n");
}
function CheatSheetPanel({ groups }) {
  const [open, setOpen] = useState(0);
  const [checks, setChecks] = useState({});
  const [copied, setCopied] = useState(false);
  const copyAll = async () => {
    const text = groups.map((g) => "## " + g.title + "\n" + blocksToText(g.blocks)).join("\n\n");
    try { await navigator.clipboard.writeText(text); setCopied(true); setTimeout(() => setCopied(false), 1800); } catch (e) { setCopied(false); }
  };
  return (
    <div>
      <button className="tp-cheat__copy" onClick={copyAll}><Icon name="copy" /> {copied ? "COPIED ✓" : "SAVE ALL AS REFERENCE (COPY)"}</button>
      {groups.map((g, i) => {
        const isChecklist = /checklist/i.test(g.title);
        return (
          <div key={i} className="tp-cheat__item">
            <div className="tp-cheat__head" onClick={() => setOpen(open === i ? -1 : i)}>
              <span>{g.title}</span><Icon name={open === i ? "minus" : "plus"} />
            </div>
            {open === i && (
              <div className="tp-cheat__body">
                {isChecklist ? (
                  (g.blocks.find((b) => b.type === "list")?.items || []).map((it, ci) => {
                    const key = i + "-" + ci; const done = checks[key];
                    return (
                      <div key={ci} className={"tp-check" + (done ? " is-done" : "")} onClick={() => setChecks({ ...checks, [key]: !done })}>
                        <span className={"tp-check__box" + (done ? " is-on" : "")}>{done && <Icon name="check" />}</span>
                        <span className="tp-check__t"><RichText text={it} /></span>
                      </div>
                    );
                  })
                ) : <Blocks blocks={g.blocks} />}
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

/* ==========================================================================
   SECTIONVIEW — per-section routing for all 23 sections (S00–S22)
   ========================================================================== */
const dropTable = (blocks) => (blocks || []).filter((b) => b.type !== "table");
const onlyTables = (blocks) => (blocks || []).filter((b) => b.type === "table");
const dropBigOrdered = (blocks) => (blocks || []).filter((b) => !(b.type === "list" && b.ordered && b.items.length >= 7));

function SectionView({ section, quiz, saveQuiz, activeSplit, setActiveSplit, scrollTo, allRead, doneDate }) {
  const n = section.num;
  const body = () => {
    switch (n) {
      case 0: /* WELCOME + ONBOARDING */
        return (<>
          <DisclaimerBanner text={CONTENT.disclaimer} />
          <HeroVisual img="body" alt="Wireframe body in a targeting reticle" caption="THE BODY AS A PRECISION SYSTEM — THE TRAINING PROTOCOL" />
          <Blocks blocks={section.howto} />
          <HierarchyPyramid scrollTo={scrollTo} />
          <OnboardingQuiz answers={quiz} save={saveQuiz} />
          <PullQuote text="The perfect program run 60% of the time loses to a good-enough program run 95% of the time." />
        </>);
      case 1: /* HOW MUSCLE GROWS */
        return (<>
          <HeroVisual img="mechanisms" alt="Three mechanisms of hypertrophy" caption="THREE MECHANISMS — BRIGHTNESS ENCODES THE HIERARCHY" />
          <Blocks blocks={dropBigOrdered(section.blocks)} />
          <SubHead title="The Three Mechanisms — Tap to Explore" />
          <ThreeMechanisms />
          <SubHead title="Twelve Myths Worth Killing Now" />
          <MythBuster myths={section.myths} />
        </>);
      case 2: /* FOUNDATIONS + VOLUME */
        return (<>
          <HeroVisual img="spectrum" alt="Effort intensity spectrum" caption="THE EFFECTIVE-REP SPECTRUM — TOO EASY / OPTIMAL / FAILURE" />
          <EffectiveRepVisual />
          <Blocks blocks={section.blocks} />
          <VolumeTracker />
        </>);
      case 4: /* MUSCLE GROUP GUIDE */
        return (<>
          <Blocks blocks={section.intro_blocks} />
          <MuscleGroupGuide muscles={section.muscles} />
        </>);
      case 5: /* CHOOSING EXERCISES */
        return (<>
          <Blocks blocks={section.blocks} />
          <ExerciseScorer />
        </>);
      case 7: /* RIR & RPE */
        return (<>
          <HeroVisual img="thermo" alt="RIR thermometer gauge" caption="THE 1–3 RIR WORKING ZONE" />
          <RIRGauge />
          <Blocks blocks={section.blocks} />
          <EffectiveRepVisual />
        </>);
      case 8: /* PROGRAM DESIGN */
        return (<>
          <div className="tp-flow">
            <div className="tp-flow__step"><div className="tp-flow__sn">01</div><div className="tp-flow__st">Warm-up</div></div>
            <span className="tp-flow__arrow">→</span>
            <div className="tp-flow__step"><div className="tp-flow__sn">02</div><div className="tp-flow__st">Compounds</div></div>
            <span className="tp-flow__arrow">→</span>
            <div className="tp-flow__step"><div className="tp-flow__sn">03</div><div className="tp-flow__st">Isolation</div></div>
          </div>
          <Blocks blocks={section.blocks} />
        </>);
      case 9: /* SPLIT COMPARISONS */
        return (<>
          <SplitComparison quizDays={quiz && quiz.days} />
          <Blocks blocks={section.blocks} />
        </>);
      case 10: /* PROGRESSION METHODS */
        return (<>
          <HeroVisual img="progression" alt="Three-node progression line" caption="BEGINNER → INTERMEDIATE → ADVANCED PROGRESSION" />
          <Blocks blocks={dropTable(section.blocks)} />
          <SubHead title="Worked Examples — Tap a Stage" />
          <ProgressionTracker tables={onlyTables(section.blocks)} />
        </>);
      case 11: /* PERIODIZATION */
        return (<>
          <Blocks blocks={section.blocks} />
          <MesocyclePlanner />
        </>);
      case 14: /* BREAKING PLATEAUS */
        return (<>
          <Blocks blocks={dropBigOrdered(section.blocks)} />
          <SubHead title="Plateau Diagnosis Flow" />
          <PlateauDiagnostic steps={(section.blocks.find((b) => b.type === "list" && b.ordered && b.items.length >= 7) || {}).items} />
        </>);
      case 18: /* COMPLETE PROGRAMS */
        return (<>
          <Blocks blocks={section.intro_blocks} />
          <ProgramSelector groups={section.groups} quiz={quiz} />
          <div className="tp-xsell-lbl">PAIRS WITH</div>
          <UpsellCard tag="THE OTHER HALF OF THE EQUATION" name="The Diet Protocol" desc="Calories, protein, and the fat-loss-without-muscle-loss math that makes the training in this guide show up visibly." cta="VIEW DIET PROTOCOL" />
        </>);
      case 19: /* PERSONAL SPLITS */
        return (<>
          <Blocks blocks={section.intro_blocks} />
          <PersonalSplitsToggle groups={section.groups} active={activeSplit} setActive={setActiveSplit} hasProgram={!!(quiz && quiz.days)} />
        </>);
      case 20: /* FAQ */
        return <FAQAccordion faqs={section.faqs} />;
      case 21: /* CHEAT SHEETS */
        return <CheatSheetPanel groups={section.groups} />;
      case 22: /* CONCLUSION */
        return (<>
          <Blocks blocks={section.blocks} />
          <PullQuote text="Long-term muscle = (Good program × Consistent effort × Progressive overload) × Time." />
          <HeroVisual img="body" alt="Wireframe body bookend" caption="THE SYSTEM, OPTIMIZED — MOGWARD" />
          <div className="tp-xsell-lbl">CONTINUE THE SYSTEM</div>
          <UpsellCard tag="STEP 2 OF THE BUILD" name="The Diet Protocol" desc="The matching system for calories, protein, and the fat-loss-without-muscle-loss math that makes this training pay off visibly." cta="VIEW DIET PROTOCOL" />
          <CoachingCrossSell />
          <CompletionBadge show={allRead} date={doneDate} total={23} />
        </>);
      default:
        return <Blocks blocks={section.blocks} />;
    }
  };
  return (
    <>
      <SectionHeader code={section.code} category={section.category} title={section.title} />
      {body()}
    </>
  );
}

/* ==========================================================================
   SIDEBAR — OnboardingQuizStatus
   ========================================================================== */
function OnboardingQuizStatus({ quiz, activeSplit, scrollTo }) {
  const route = routeQuiz(quiz);
  const set = quiz || {};
  const has = set.age || set.days || set.goal || set.equip;
  return (
    <div className="tp-status">
      <div className="tp-status__lbl">YOUR SETUP</div>
      {!has ? (
        <div className="tp-status__cta" style={{ cursor: "pointer" }} onClick={() => scrollTo("section-0")}>NOT SET — take the quiz →</div>
      ) : (
        <>
          <div className="tp-status__badges">
            {set.age && <span className="tp-status__b">{set.age}</span>}
            {set.days && <span className="tp-status__b">{set.days} days/wk</span>}
            {set.goal && <span className="tp-status__b">{set.goal}</span>}
            {set.equip && <span className="tp-status__b">{set.equip === "Full" ? "Full gym" : set.equip === "DB" ? "DB + bar" : "Minimal"}</span>}
          </div>
          {route && <div className="tp-status__match"><b>Split:</b> {route.split}</div>}
          {activeSplit && <div className="tp-status__match"><b>Active:</b> {activeSplit}</div>}
        </>
      )}
    </div>
  );
}

/* ==========================================================================
   APP
   ========================================================================== */
export default function TrainingProtocol() {
  const sections = CONTENT.sections;
  const [activeIdx, setActiveIdx] = useState(0);
  const [mobileNav, setMobileNav] = useState(false);
  const [completed, setCompleted] = useState(() => new Set());
  const [quiz, saveQuiz] = useStored(K_QUIZ, {});
  const [activeSplit, saveSplit] = useStored(K_SPLIT, null);
  const contentRef = useRef(null);
  const sectionEls = useRef({});

  const total = sections.length;
  const allRead = completed.size >= total;
  const doneDate = useMemo(() => new Date().toLocaleDateString("en-US", { year: "numeric", month: "short", day: "numeric" }), []);

  /* scroll-based active-section detection */
  useEffect(() => {
    const root = contentRef.current; if (!root) return;
    let raf = 0;
    const onScroll = () => {
      if (raf) return;
      raf = requestAnimationFrame(() => {
        raf = 0;
        const trigger = root.getBoundingClientRect().top + 140;
        let cur = 0;
        sections.forEach((s, i) => {
          const el = sectionEls.current[s.id];
          if (el && el.getBoundingClientRect().top <= trigger) cur = i;
        });
        setActiveIdx(cur);
      });
    };
    root.addEventListener("scroll", onScroll, { passive: true });
    onScroll();
    return () => root.removeEventListener("scroll", onScroll);
  }, [sections]);

  const scrollTo = useCallback((id) => {
    const el = sectionEls.current[id];
    if (el && contentRef.current) {
      contentRef.current.scrollTo({ top: el.offsetTop - 12, behavior: "smooth" });
    }
  }, []);

  const toggleRead = useCallback((i) => {
    setCompleted((prev) => {
      const next = new Set(prev);
      next.has(i) ? next.delete(i) : next.add(i);
      return next;
    });
  }, []);

  const activeLevel = useMemo(() => {
    const lv = HIER.find((h) => h.to === activeIdx);
    return lv ? lv.rank : null;
  }, [activeIdx]);

  const pct = Math.round((completed.size / total) * 100);

  return (
    <div className="fp-app">
      <StyleSheet />
      <header className="fp-header">
        <div className="fp-header__left">
          <button className="fp-burger" onClick={() => setMobileNav((v) => !v)} aria-label="Menu"><span /><span /><span /></button>
          <div className="fp-logo"><span className="fp-logo__badge">M</span><span className="fp-logo__word">MOGWARD</span></div>
        </div>
        <div className="fp-header__right">
          <span className="fp-header__sec">{sections[activeIdx].code}</span>
          <span className="fp-header__title">TRAINING PROTOCOL</span>
        </div>
      </header>

      <div className="fp-layout">
        <aside className={"fp-sidebar" + (mobileNav ? " is-open" : "")}>
          <div className="fp-sidebar__pyr">
            <OnboardingQuizStatus quiz={quiz} activeSplit={activeSplit} scrollTo={scrollTo} />
            <HierarchyMini activeLevel={activeLevel} />
          </div>
          <nav className="fp-nav">
            {sections.map((s, i) => (
              <button key={s.id} className={"fp-nav__item" + (activeIdx === i ? " is-active" : "") + (completed.has(i) ? " is-done" : "")} onClick={() => { scrollTo(s.id); setMobileNav(false); }}>
                <span className="fp-nav__code">{s.code}</span>
                <span className="fp-nav__label">{s.short}</span>
                {completed.has(i) && <span className="fp-nav__chk"><Icon name="check" /></span>}
              </button>
            ))}
          </nav>
          <div className="fp-sidebar__progress">
            <div className="fp-sidebar__ptop"><span>{completed.size} / {total} READ</span><span className="fp-sidebar__pct">{pct}%</span></div>
            <div className="fp-pbar"><div className="fp-pbar__fill" style={{ width: pct + "%" }} /></div>
          </div>
          <div className="fp-sidebar__foot">
            {allRead
              ? <button className="fp-complete is-unlocked" onClick={() => scrollTo("section-22")}>VIEW CERTIFICATE</button>
              : <button className="fp-complete" onClick={() => toggleRead(activeIdx)}>{completed.has(activeIdx) ? "UNMARK THIS SECTION" : "MARK SECTION READ"}</button>}
            <p className="fp-sidebar__hint">Mark all {total} sections read to unlock your certificate.</p>
          </div>
        </aside>

        <main className="fp-content" ref={contentRef}>
          <div className="fp-content__inner">
            {sections.map((s, i) => (
              <section key={s.id} id={s.id} ref={(el) => (sectionEls.current[s.id] = el)} className="fp-section">
                <SectionView
                  section={s} quiz={quiz} saveQuiz={saveQuiz}
                  activeSplit={activeSplit} setActiveSplit={saveSplit}
                  scrollTo={scrollTo} allRead={allRead} doneDate={doneDate}
                />
                <div style={{ marginTop: 24, display: "flex", justifyContent: "flex-end" }}>
                  <button className={"fp-markread" + (completed.has(i) ? " is-done" : "")} onClick={() => toggleRead(i)}>
                    {completed.has(i) ? <><Icon name="check" /> MARKED AS READ</> : "MARK AS READ"}
                  </button>
                </div>
              </section>
            ))}
            <footer className="fp-footer">
              <span className="fp-logo__badge">M</span> MOGWARD · THE TRAINING PROTOCOL
            </footer>
          </div>
        </main>
      </div>
    </div>
  );
}

function StyleSheet() { return <style>{`@import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@400;500;600;700&family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500;700&display=swap');

.fp-app{
  --bg-primary:#0a0a0c; --bg-secondary:#111114; --bg-tertiary:#1a1a1f; --bg-hover:#22222a;
  --border-subtle:#2a2a32; --border-visible:#3a3a45;
  --text-primary:#f0f0f0; --text-secondary:#a8a3bd; --text-muted:#5f5b73;
  --accent-green-text:#4ade80; --accent-red-text:#f87171;
  --accent-primary:#9d8cf5; --accent-primary-bright:#b9aefb; --accent-primary-dim:#4f4480;
  --accent-glow:rgba(157,140,245,0.35); --border-accent:#6e5fc4;
  --accent-warn:#c9a84c; --accent-warn-bright:#e8c46a;
  --font-heading:'Space Grotesk','Inter',sans-serif; --font-body:'Inter',sans-serif; --font-mono:'JetBrains Mono',monospace;
  --radius-sm:4px; --radius-md:8px; --radius-lg:12px; --transition:150ms ease; --header-h:56px; --sidebar-w:260px;
  background:var(--bg-primary); color:var(--text-primary); font-family:var(--font-body);
  font-size:16px; line-height:1.65; min-height:100vh; -webkit-font-smoothing:antialiased;
}
.fp-app *{box-sizing:border-box;}
.fp-app button{font-family:inherit; cursor:pointer;}
.fp-code{font-family:var(--font-mono); font-size:.85em; background:var(--bg-tertiary); padding:1px 5px; border-radius:4px; color:var(--accent-primary-bright);}

/* HEADER */
.fp-header{position:fixed; top:0; left:0; right:0; height:var(--header-h); z-index:40;
  display:flex; align-items:center; justify-content:space-between; padding:0 20px;
  background:var(--bg-secondary); border-bottom:1px solid var(--border-accent);
  box-shadow:0 1px 0 var(--accent-glow), 0 6px 24px -12px var(--accent-glow);}
.fp-header__left,.fp-header__right{display:flex; align-items:center; gap:12px;}
.fp-logo{display:flex; align-items:center; gap:9px;}
.fp-logo__badge{display:grid; place-items:center; width:26px; height:26px; border-radius:6px;
  background:linear-gradient(135deg,var(--accent-primary),var(--accent-primary-dim)); color:#0a0a0c;
  font-family:var(--font-heading); font-weight:700; font-size:15px; box-shadow:0 0 14px var(--accent-glow);}
.fp-logo__word{font-family:var(--font-heading); font-weight:700; letter-spacing:.14em; font-size:15px;}
.fp-header__title{font-family:var(--font-heading); font-weight:600; letter-spacing:.16em; font-size:12px; color:var(--accent-primary-bright);}
.fp-header__sec{font-family:var(--font-mono); font-size:12px; color:var(--accent-primary); border:1px solid var(--border-accent);
  padding:3px 8px; border-radius:5px; box-shadow:0 0 10px var(--accent-glow);}
.fp-burger{display:none; flex-direction:column; gap:4px; background:none; border:none; padding:6px;}
.fp-burger span{width:20px; height:2px; background:var(--text-secondary); border-radius:2px;}

/* LAYOUT */
.fp-layout{display:flex; padding-top:var(--header-h); min-height:100vh;}
.fp-sidebar{position:fixed; top:var(--header-h); bottom:0; left:0; width:var(--sidebar-w); z-index:30;
  background:var(--bg-secondary); border-right:1px solid var(--border-subtle);
  display:flex; flex-direction:column; overflow-y:auto;}
.fp-sidebar__pyr{padding:16px 16px 8px;}
.fp-sidebar__pyrlbl,.fp-sidebar__pyrcard__lbl{font-family:var(--font-mono); font-size:9.5px; letter-spacing:.14em; color:var(--text-muted); margin-bottom:10px; text-align:center;}

/* mini pyramid (sidebar) */
.fp-pyr{display:flex; flex-direction:column; align-items:center; gap:4px;}
.fp-pyr--mini .fp-pyr__lvl{height:30px;}
.fp-pyr__lvl{position:relative; display:flex; align-items:center; justify-content:center; gap:8px;
  height:46px; border:1px solid var(--border-visible); border-radius:6px; background:var(--bg-tertiary);
  color:var(--text-secondary); transition:var(--transition); padding:0 10px; width:60%;}
.fp-pyr__lvl:hover{border-color:var(--border-accent); color:var(--text-primary);}
.fp-pyr__lvl.is-active{border-color:var(--accent-primary); color:var(--text-primary);
  background:linear-gradient(180deg,rgba(157,140,245,.18),rgba(157,140,245,.04)); box-shadow:0 0 16px var(--accent-glow);}
.fp-pyr__lvl.is-done .fp-pyr__n{color:var(--accent-green-text);}
.fp-pyr__n{font-family:var(--font-mono); font-size:13px; color:var(--accent-primary); font-weight:700;}
.fp-pyr__ic{font-size:15px; color:var(--accent-primary-bright); display:flex;}
.fp-pyr__lbl{font-size:12px; font-weight:500; white-space:nowrap;}
.fp-pyr__chk{position:absolute; right:6px; font-size:12px; color:var(--accent-green-text); display:flex;}
.fp-pyr--mini .fp-pyr__lbl{display:none;}

/* full pyramid card (S00) */
.fp-pyrcard{margin:26px 0; padding:24px; border:1px solid var(--border-accent); border-radius:var(--radius-lg);
  background:radial-gradient(120% 80% at 50% 0%, rgba(157,140,245,.12), transparent 70%), var(--bg-secondary);}
.fp-pyrcard__lbl{font-family:var(--font-mono); font-size:10px; letter-spacing:.16em; color:var(--text-muted); text-align:center; margin-bottom:16px;}
.fp-pyrcard .fp-pyr__lvl{height:54px;}

/* progress */
.fp-sidebar__progress{padding:12px 16px; border-top:1px solid var(--border-subtle);}
.fp-sidebar__ptop{display:flex; justify-content:space-between; font-family:var(--font-mono); font-size:9.5px; letter-spacing:.12em; color:var(--text-muted); margin-bottom:7px;}
.fp-sidebar__pct{color:var(--accent-primary-bright);}
.fp-pbar{height:5px; background:var(--bg-tertiary); border-radius:3px; overflow:hidden;}
.fp-pbar__fill{height:100%; background:linear-gradient(90deg,var(--accent-primary-dim),var(--accent-primary-bright)); box-shadow:0 0 10px var(--accent-glow); transition:width .4s ease;}
.fp-sidebar__count{font-family:var(--font-mono); font-size:9.5px; color:var(--text-muted); margin-top:7px; letter-spacing:.1em;}

/* nav */
.fp-nav{display:flex; flex-direction:column; padding:8px; gap:2px; flex:1;}
.fp-nav__item{position:relative; display:flex; align-items:center; gap:10px; padding:9px 10px; border:none;
  background:none; border-radius:6px; text-align:left; color:var(--text-secondary); transition:var(--transition); border-left:2px solid transparent;}
.fp-nav__item:hover{background:var(--bg-hover); color:var(--text-primary);}
.fp-nav__item.is-active{background:var(--bg-tertiary); color:var(--text-primary); border-left-color:var(--accent-primary);}
.fp-nav__code{font-family:var(--font-mono); font-size:11px; color:var(--accent-primary-dim); width:30px; flex-shrink:0;}
.fp-nav__item.is-active .fp-nav__code{color:var(--accent-primary-bright);}
.fp-nav__item.is-done .fp-nav__code{color:var(--accent-green-text);}
.fp-nav__label{font-size:12px; font-weight:500; letter-spacing:.04em; line-height:1.25;}
.fp-nav__chk{margin-left:auto; font-size:13px; color:var(--accent-green-text); display:flex;}

/* sidebar foot */
.fp-sidebar__foot{padding:14px 16px 18px; border-top:1px solid var(--border-subtle);}
.fp-complete{width:100%; padding:11px; border:1px solid var(--border-accent); border-radius:8px; background:var(--bg-tertiary);
  color:var(--accent-primary-bright); font-family:var(--font-heading); font-weight:600; letter-spacing:.12em; font-size:12px; transition:var(--transition);}
.fp-complete:hover{background:var(--bg-hover); box-shadow:0 0 16px var(--accent-glow);}
.fp-complete.is-unlocked{background:linear-gradient(135deg,var(--accent-primary),var(--accent-primary-dim)); color:#0a0a0c; border-color:transparent; box-shadow:0 0 20px var(--accent-glow);}
.fp-sidebar__hint{font-size:10.5px; color:var(--text-muted); margin:9px 0 0; line-height:1.4;}

/* CONTENT */
.fp-content{margin-left:var(--sidebar-w); flex:1; height:calc(100vh - var(--header-h)); overflow-y:auto; scroll-behavior:smooth;}
.fp-content__inner{max-width:860px; margin:0 auto; padding:40px 60px 120px;}
.fp-section{padding:34px 0 26px; border-bottom:1px solid var(--border-subtle); scroll-margin-top:20px;}

/* section header */
.fp-sechead{margin-bottom:22px;}
.fp-sechead__top{display:flex; align-items:center; gap:12px; margin-bottom:10px;}
.fp-sechead__code{font-family:var(--font-mono); font-size:18px; color:var(--accent-primary); font-weight:600; text-shadow:0 0 14px var(--accent-glow);}
.fp-sechead__tag{font-family:var(--font-mono); font-size:10px; letter-spacing:.16em; color:var(--accent-primary-bright);
  border:1px solid var(--border-accent); padding:3px 9px; border-radius:20px;}
.fp-sechead__title{font-family:var(--font-heading); font-size:30px; font-weight:700; line-height:1.1; margin:0 0 14px; letter-spacing:-.01em;}
.fp-sechead__rule{height:1px; background:linear-gradient(90deg,var(--accent-primary),transparent);}
.fp-subhead{font-family:var(--font-heading); font-size:20px; font-weight:600; margin:30px 0 12px; color:var(--text-primary);}

/* prose */
.fp-p{margin:0 0 15px; color:var(--text-primary);}
.fp-h3{font-family:var(--font-heading); font-size:18px; font-weight:600; margin:24px 0 10px;}
.fp-h4{font-family:var(--font-heading); font-size:15px; font-weight:600; margin:18px 0 8px; color:var(--text-secondary); letter-spacing:.02em;}
/* bold lead-ins read as highlighted mini-headings */
.fp-app strong, .fp-app b{color:var(--accent-primary-bright); font-weight:700;}
/* unordered lists — clearly visible glowing violet bullets */
.fp-ul{list-style:none; margin:0 0 16px; padding-left:24px;}
.fp-ul li{position:relative; margin-bottom:9px; line-height:1.6;}
.fp-ul li::before{content:""; position:absolute; left:-18px; top:9px; width:6px; height:6px; border-radius:50%; background:var(--accent-primary-bright); box-shadow:0 0 8px var(--accent-glow);}
/* ordered lists — accent mono numerals */
.fp-ol{margin:0 0 16px; padding-left:26px;}
.fp-ol li{margin-bottom:9px; line-height:1.6; padding-left:2px;}
.fp-ol li::marker{color:var(--accent-primary-bright); font-family:var(--font-mono); font-weight:700;}
.fp-quote{margin:16px 0; padding:14px 18px; border-left:3px solid var(--accent-primary-dim); background:var(--bg-secondary); border-radius:0 8px 8px 0; color:var(--text-secondary);}
.fp-pre{background:var(--bg-secondary); border:1px solid var(--border-subtle); border-radius:8px; padding:14px; overflow-x:auto; font-family:var(--font-mono); font-size:13px; margin:0 0 16px;}
.fp-checklist{list-style:none; margin:0 0 16px; padding:0;}
.fp-checklist li{display:flex; gap:10px; align-items:flex-start; margin-bottom:9px;}
.fp-checklist__box{flex-shrink:0; width:20px; height:20px; border-radius:5px; display:grid; place-items:center; font-size:13px; background:rgba(157,140,245,.12); color:var(--accent-primary-bright); border:1px solid var(--border-accent); margin-top:1px;}

/* table */
.fp-tablewrap{overflow-x:auto; margin:0 0 18px; border:1px solid var(--border-subtle); border-radius:var(--radius-md);}
.fp-table{width:100%; border-collapse:collapse; font-size:13.5px; min-width:480px;}
.fp-table th{background:var(--bg-tertiary); text-align:left; padding:11px 14px; font-family:var(--font-mono); font-size:10.5px; letter-spacing:.08em; color:var(--accent-primary-bright); text-transform:uppercase; border-bottom:1px solid var(--border-visible);}
.fp-table td{padding:11px 14px; border-bottom:1px solid var(--border-subtle); color:var(--text-secondary); vertical-align:top;}
.fp-table tr:last-child td{border-bottom:none;}

/* hero */
.fp-hero{margin:0 0 22px;}
.fp-hero__frame{position:relative; border:1px solid var(--border-accent); border-radius:var(--radius-lg); overflow:hidden;
  box-shadow:0 0 40px -8px var(--accent-glow); background:#000;}
.fp-hero__frame::after{content:""; position:absolute; inset:0; box-shadow:inset 0 0 60px -20px var(--accent-glow); pointer-events:none;}
.fp-hero__frame img{width:100%; display:block;}
.fp-hero__cap{font-size:12.5px; font-style:italic; color:var(--text-muted); margin-top:9px; text-align:center; line-height:1.5;}

/* callouts */
.fp-callout{margin:16px 0; padding:15px 18px; border-radius:var(--radius-md); background:var(--bg-secondary); border-left:3px solid var(--accent-primary);}
.fp-callout--practical{background:var(--bg-tertiary); border-left-color:var(--accent-primary-bright);}
.fp-callout--caution{border-left-color:var(--accent-warn); background:rgba(201,168,76,.06);}
.fp-callout--science{border-left-color:var(--accent-primary);}
.fp-callout__label{display:flex; align-items:center; gap:7px; font-family:var(--font-mono); font-size:10.5px; letter-spacing:.14em; margin-bottom:8px; color:var(--accent-primary-bright);}
.fp-callout--caution .fp-callout__label{color:var(--accent-warn-bright);}
.fp-callout__body .fp-p:last-child{margin-bottom:0;}

/* pull quote */
.fp-pullquote{position:relative; margin:24px 0; padding:24px 26px 24px 56px; border:1px solid var(--border-accent); border-radius:var(--radius-lg);
  background:radial-gradient(120% 100% at 0% 0%, rgba(157,140,245,.12), transparent 60%), var(--bg-secondary);}
.fp-pullquote__mark{position:absolute; left:18px; top:6px; font-family:var(--font-heading); font-size:54px; color:var(--accent-primary-dim); line-height:1;}
.fp-pullquote p{margin:0; font-family:var(--font-heading); font-size:19px; font-weight:500; line-height:1.5; color:var(--text-primary);}

/* disclaimer */
.fp-disc{margin:0 0 22px; padding:16px 18px; border:1px solid var(--accent-warn); border-radius:var(--radius-md); background:rgba(201,168,76,.06);}
.fp-disc__head{display:flex; align-items:center; justify-content:space-between; margin-bottom:8px;}
.fp-disc__tag{display:flex; align-items:center; gap:7px; font-family:var(--font-mono); font-size:10.5px; letter-spacing:.14em; color:var(--accent-warn-bright);}
.fp-disc__x{background:none; border:none; color:var(--text-muted); font-size:16px; display:flex; padding:2px;}
.fp-disc__x:hover{color:var(--text-primary);}
.fp-disc p{margin:0; font-size:13.5px; color:var(--text-secondary); line-height:1.6;}
.fp-disc--collapsed{display:flex; align-items:center; gap:8px; width:100%; justify-content:center; color:var(--accent-warn-bright);
  font-family:var(--font-mono); font-size:11px; letter-spacing:.08em; padding:9px;}

/* upsell */
.fp-upsell{margin:22px 0; padding:20px; border:1px solid var(--border-accent); border-radius:var(--radius-lg); background:var(--bg-tertiary);
  box-shadow:0 0 30px -16px var(--accent-glow);}
.fp-upsell__tag{font-family:var(--font-mono); font-size:9.5px; letter-spacing:.16em; color:var(--accent-primary-bright); border:1px solid var(--border-accent); padding:3px 8px; border-radius:20px;}
.fp-upsell__name{font-family:var(--font-heading); font-size:20px; font-weight:700; margin:12px 0 6px;}
.fp-upsell__desc{font-size:14px; color:var(--text-secondary); margin:0 0 14px;}
.fp-upsell__cta{display:inline-flex; align-items:center; gap:8px; font-family:var(--font-heading); font-weight:600; font-size:13px; letter-spacing:.08em;
  color:#0a0a0c; background:linear-gradient(135deg,var(--accent-primary),var(--accent-primary-dim)); padding:9px 16px; border-radius:8px; box-shadow:0 0 16px var(--accent-glow);}
.fp-upsell-pair{display:grid; grid-template-columns:1fr 1fr; gap:16px;}
.fp-upsell-pair .fp-upsell{margin:0;}

/* timeline split */
.fp-tl{display:grid; grid-template-columns:1fr 1fr; gap:16px; margin:22px 0;}
.fp-tl__col{padding:18px; border-radius:var(--radius-lg); border:1px solid var(--border-subtle); background:var(--bg-secondary);}
.fp-tl__col--slow{border-color:var(--border-accent); box-shadow:0 0 26px -16px var(--accent-glow);}
.fp-tl__head{font-family:var(--font-heading); font-weight:700; font-size:13px; letter-spacing:.12em; display:flex; flex-direction:column; gap:2px; margin-bottom:14px; color:var(--accent-primary-bright);}
.fp-tl__col--fast .fp-tl__head{color:var(--text-secondary);}
.fp-tl__head span{font-family:var(--font-mono); font-size:9.5px; letter-spacing:.1em; color:var(--text-muted); font-weight:400;}
.fp-tl__row{display:flex; gap:11px; align-items:flex-start; margin-bottom:11px;}
.fp-tl__ic{font-size:17px; color:var(--accent-primary); margin-top:1px; display:flex;}
.fp-tl__col--fast .fp-tl__ic{color:var(--text-secondary);}
.fp-tl__row b{display:block; font-size:14px; font-weight:600;}
.fp-tl__row i{display:block; font-size:12px; font-style:normal; color:var(--text-muted);}
.fp-tl__foot{font-size:11.5px; color:var(--text-muted); margin:12px 0 0; font-style:italic; line-height:1.45;}

/* body fat table */
.fp-bft{margin:8px 0 18px;}
.fp-bft__toggle{display:inline-flex; border:1px solid var(--border-visible); border-radius:8px; overflow:hidden; margin-bottom:14px;}
.fp-bft__toggle button{padding:8px 22px; background:var(--bg-tertiary); border:none; color:var(--text-secondary); font-family:var(--font-mono); font-size:11px; letter-spacing:.12em; transition:var(--transition);}
.fp-bft__toggle button.is-on{background:linear-gradient(135deg,var(--accent-primary),var(--accent-primary-dim)); color:#0a0a0c; font-weight:600;}
.fp-bft__rows{display:flex; flex-direction:column; gap:8px;}
.fp-bft__row{border:1px solid var(--border-subtle); border-radius:var(--radius-md); background:var(--bg-secondary); overflow:hidden;}
.fp-bft__row.is-target{border-color:var(--accent-primary); box-shadow:0 0 18px -4px var(--accent-glow); background:linear-gradient(180deg,rgba(157,140,245,.08),transparent);}
.fp-bft__head{width:100%; display:flex; align-items:center; gap:12px; padding:13px 16px; background:none; border:none; color:var(--text-primary);}
.fp-bft__range{font-family:var(--font-mono); font-size:15px; color:var(--accent-primary-bright); min-width:90px; text-align:left;}
.fp-bft__badge{font-family:var(--font-mono); font-size:9px; letter-spacing:.12em; color:#0a0a0c; background:var(--accent-primary); padding:2px 8px; border-radius:12px;}
.fp-bft__tg{margin-left:auto; font-size:15px; color:var(--text-muted); display:flex;}
.fp-bft__note{margin:0; padding:0 16px 14px; font-size:13.5px; color:var(--text-secondary); line-height:1.55;}
.fp-bft__cap{font-size:12px; color:var(--text-muted); margin:12px 0 0; line-height:1.5; font-style:italic;}

/* posture compare */
.fp-pc{display:grid; grid-template-columns:1fr 1fr; gap:14px; margin:18px 0;}
.fp-pc__side{padding:16px; border-radius:var(--radius-lg); border:1px solid var(--border-subtle); background:var(--bg-secondary);}
.fp-pc__side--avoid{opacity:.82;}
.fp-pc__side--ok{border-color:var(--accent-primary); box-shadow:0 0 26px -14px var(--accent-glow); background:linear-gradient(180deg,rgba(157,140,245,.08),transparent);}
.fp-pc__top{display:flex; align-items:center; gap:8px; font-family:var(--font-mono); font-size:11px; letter-spacing:.14em; margin-bottom:10px; color:var(--text-muted);}
.fp-pc__side--ok .fp-pc__top{color:var(--accent-primary-bright);}
.fp-pc__mark{display:grid; place-items:center; width:22px; height:22px; border-radius:50%; font-size:13px;}
.fp-pc__side--avoid .fp-pc__mark{background:rgba(248,113,113,.12); color:var(--accent-red-text);}
.fp-pc__side--ok .fp-pc__mark{background:rgba(157,140,245,.16); color:var(--accent-primary-bright);}
.fp-pc__side h5{font-family:var(--font-heading); font-size:15px; margin:0 0 9px; font-weight:600;}
.fp-pc__side ul{list-style:none; margin:0; padding:0;}
.fp-pc__side li{font-size:13px; color:var(--text-secondary); margin-bottom:7px; padding-left:14px; position:relative; line-height:1.45;}
.fp-pc__side li::before{content:"–"; position:absolute; left:0; color:var(--accent-primary-dim);}

/* stepper */
.fp-stepper{list-style:none; margin:18px 0; padding:0; position:relative;}
.fp-stepper::before{content:""; position:absolute; left:13px; top:6px; bottom:6px; width:2px; background:linear-gradient(180deg,var(--accent-primary),var(--accent-primary-dim));}
.fp-stepper__item{display:flex; gap:14px; margin-bottom:16px; position:relative;}
.fp-stepper__dot{flex-shrink:0; width:28px; height:28px; border-radius:50%; display:grid; place-items:center; font-family:var(--font-mono); font-size:13px; font-weight:700;
  background:var(--bg-tertiary); border:1px solid var(--accent-primary); color:var(--accent-primary-bright); box-shadow:0 0 12px var(--accent-glow); z-index:1;}
.fp-stepper__item b{display:block; font-family:var(--font-heading); font-size:14px; font-weight:600; margin:3px 0 4px; letter-spacing:.04em;}
.fp-stepper__item p{margin:0; font-size:13.5px; color:var(--text-secondary); line-height:1.5;}

/* jump link */
.fp-jump{display:inline-flex; align-items:center; gap:8px; margin:6px 0 14px; padding:8px 14px; background:var(--bg-tertiary);
  border:1px solid var(--border-accent); border-radius:8px; color:var(--accent-primary-bright); font-size:12.5px; transition:var(--transition);}
.fp-jump:hover{box-shadow:0 0 14px var(--accent-glow); background:var(--bg-hover);}

/* hydration */
.fp-hydro{display:grid; grid-template-columns:1fr 120px; gap:20px; margin:18px 0; padding:20px; border:1px solid var(--border-accent); border-radius:var(--radius-lg);
  background:radial-gradient(100% 100% at 0% 0%, rgba(157,140,245,.08), transparent 60%), var(--bg-secondary);}
.fp-hydro__inrow label{font-family:var(--font-mono); font-size:10px; letter-spacing:.12em; color:var(--text-muted); display:block; margin-bottom:7px;}
.fp-hydro__input{display:flex; gap:8px;}
.fp-hydro__input input{flex:1; min-width:0; background:var(--bg-tertiary); border:1px solid var(--border-visible); border-radius:8px; padding:10px 12px;
  color:var(--text-primary); font-family:var(--font-mono); font-size:16px;}
.fp-hydro__input input:focus{outline:none; border-color:var(--accent-primary); box-shadow:0 0 0 3px rgba(157,140,245,.15);}
.fp-hydro__unit{display:inline-flex; border:1px solid var(--border-visible); border-radius:8px; overflow:hidden;}
.fp-hydro__unit button{padding:0 12px; background:var(--bg-tertiary); border:none; color:var(--text-secondary); font-family:var(--font-mono); font-size:12px;}
.fp-hydro__unit button.is-on{background:var(--accent-primary); color:#0a0a0c; font-weight:600;}
.fp-hydro__out{margin:18px 0; display:flex; flex-direction:column;}
.fp-hydro__big{font-family:var(--font-heading); font-size:46px; font-weight:700; color:var(--accent-primary-bright); line-height:1; text-shadow:0 0 22px var(--accent-glow);}
.fp-hydro__unitlbl{font-family:var(--font-mono); font-size:12px; color:var(--text-secondary); letter-spacing:.1em; margin-top:4px;}
.fp-hydro__sub{font-size:12px; color:var(--text-muted); margin-top:6px;}
.fp-hydro__scale{margin-top:6px;}
.fp-hydro__scalelbl{font-family:var(--font-mono); font-size:9.5px; letter-spacing:.12em; color:var(--text-muted); display:block; margin-bottom:8px;}
.fp-hydro__swatches{display:flex; gap:6px;}
.fp-hydro__sw{flex:1; height:30px; border-radius:5px; border:1px solid var(--border-subtle); transition:var(--transition);}
.fp-hydro__sw.is-on{border-color:#fff; box-shadow:0 0 0 2px var(--accent-primary), 0 0 12px var(--accent-glow); transform:translateY(-2px);}
.fp-hydro__fb{font-size:12.5px; margin:10px 0 0; padding:7px 11px; border-radius:6px; background:var(--bg-tertiary);}
.fp-hydro__fb--good{color:var(--accent-green-text);} .fp-hydro__fb--warn{color:var(--accent-warn-bright);} .fp-hydro__fb--bad{color:var(--accent-red-text);}
.fp-hydro__cyl{display:flex; flex-direction:column; align-items:center; justify-content:flex-end;}
.fp-hydro__tube{position:relative; width:54px; height:200px; border:1.5px solid var(--border-accent); border-radius:12px; background:var(--bg-primary); overflow:hidden;}
.fp-hydro__fill{position:absolute; left:0; right:0; bottom:0; border-radius:0 0 10px 10px; box-shadow:0 0 20px var(--accent-glow); transition:height .45s ease, background .45s ease;}
.fp-hydro__mark{position:absolute; left:0; right:0; border-top:1px dashed var(--accent-primary-bright); z-index:2; pointer-events:none;}
.fp-hydro__mark span{position:absolute; right:3px; top:-13px; font-family:var(--font-mono); font-size:8px; letter-spacing:.06em; color:var(--accent-primary-bright); background:var(--bg-primary); padding:0 4px;}
.fp-hydro__status{font-family:var(--font-mono); font-size:10px; letter-spacing:.12em; color:var(--text-secondary); margin-top:9px;}

/* skincare grid */
.fp-skin{margin:8px 0 18px;}
.fp-skin__grid{display:grid; grid-template-columns:repeat(3,1fr); gap:12px;}
.fp-skin__cell{display:flex; flex-direction:column; align-items:center; gap:9px; padding:18px 10px; border:1px solid var(--border-subtle); border-radius:var(--radius-md);
  background:var(--bg-secondary); color:var(--text-secondary); transition:var(--transition);}
.fp-skin__cell:hover,.fp-skin__cell.is-open{border-color:var(--accent-primary); box-shadow:0 0 18px -6px var(--accent-glow); color:var(--text-primary); background:linear-gradient(180deg,rgba(157,140,245,.06),transparent);}
.fp-skin__ic{font-size:26px; color:var(--accent-primary-bright); display:flex;}
.fp-skin__lbl{font-family:var(--font-heading); font-size:12.5px; font-weight:600; letter-spacing:.04em;}
.fp-skin__note{margin:14px 0 0; padding:14px 16px; border:1px solid var(--border-accent); border-radius:var(--radius-md); background:var(--bg-tertiary); font-size:13.5px; color:var(--text-secondary); line-height:1.55;}
.fp-skin__note b{color:var(--accent-primary-bright);}

/* habit tracker */
.fp-track{margin:8px 0 18px; padding:18px; border:1px solid var(--border-accent); border-radius:var(--radius-lg); background:var(--bg-secondary);}
.fp-track--loading{color:var(--text-muted); font-family:var(--font-mono); font-size:12px; text-align:center; padding:40px;}
.fp-track__top{display:flex; gap:22px; align-items:center; margin-bottom:18px; flex-wrap:wrap;}
.fp-dial{position:relative; width:80px; height:80px; flex-shrink:0;}
.fp-dial svg{width:80px; height:80px;}
.fp-dial__bg{fill:none; stroke:var(--bg-tertiary); stroke-width:7;}
.fp-dial__fg{fill:none; stroke:var(--accent-primary); stroke-width:7; stroke-linecap:round; filter:drop-shadow(0 0 4px var(--accent-glow)); transition:stroke-dashoffset .5s ease;}
.fp-dial__center{position:absolute; inset:0; display:flex; flex-direction:column; align-items:center; justify-content:center;}
.fp-dial__center b{font-family:var(--font-heading); font-size:22px; color:var(--accent-primary-bright); line-height:1;}
.fp-dial__center i{font-family:var(--font-mono); font-size:8px; font-style:normal; letter-spacing:.1em; color:var(--text-muted);}
.fp-trend{flex:1; min-width:160px;}
.fp-trend__lbl{font-family:var(--font-mono); font-size:9px; letter-spacing:.12em; color:var(--text-muted); display:block; margin-bottom:6px;}
.fp-trend svg{width:100%; height:56px;}
.fp-trend__line{fill:none; stroke:var(--accent-primary); stroke-width:2; filter:drop-shadow(0 0 3px var(--accent-glow)); vector-effect:non-scaling-stroke;}
.fp-trend__dot{fill:var(--accent-primary-bright);}
.fp-track__gridwrap{overflow-x:auto;}
.fp-track__grid{border-collapse:separate; border-spacing:5px; width:100%; min-width:430px;}
.fp-track__grid th{font-family:var(--font-mono); font-size:10px; color:var(--text-muted); font-weight:400; padding-bottom:2px;}
.fp-track__rowhead{text-align:left; font-family:var(--font-body); font-size:11.5px; color:var(--text-secondary); white-space:nowrap; padding-right:8px; display:flex; align-items:center; gap:7px;}
.fp-track__ic{font-size:15px; color:var(--accent-primary); display:flex;}
.fp-track__cell{width:34px; height:34px; border-radius:7px; border:1px solid var(--border-visible); background:var(--bg-tertiary); display:grid; place-items:center; color:transparent; transition:var(--transition);}
.fp-track__cell:hover{border-color:var(--accent-primary);}
.fp-track__cell.is-on{background:linear-gradient(135deg,rgba(157,140,245,.3),rgba(157,140,245,.1)); border-color:var(--accent-primary); color:var(--accent-primary-bright); box-shadow:0 0 10px var(--accent-glow);}
.fp-track__foot{display:flex; align-items:center; justify-content:space-between; margin-top:14px; gap:10px;}
.fp-track__reset{display:inline-flex; align-items:center; gap:7px; background:var(--bg-tertiary); border:1px solid var(--border-visible); border-radius:7px; color:var(--text-secondary); font-family:var(--font-mono); font-size:10.5px; letter-spacing:.08em; padding:7px 12px;}
.fp-track__reset:hover{border-color:var(--accent-primary); color:var(--text-primary);}
.fp-track__save{font-family:var(--font-mono); font-size:10px; color:var(--text-muted);}

/* FAQ */
.fp-faq{margin-top:6px;}
.fp-faq__search{display:flex; align-items:center; gap:10px; padding:11px 14px; border:1px solid var(--border-visible); border-radius:var(--radius-md); background:var(--bg-secondary); margin-bottom:14px; color:var(--text-muted);}
.fp-faq__search input{flex:1; min-width:0; background:none; border:none; color:var(--text-primary); font-size:14px; outline:none;}
.fp-faq__search button{background:none; border:none; color:var(--text-muted); display:flex; font-size:15px;}
.fp-faq__tabs{display:flex; flex-wrap:wrap; gap:7px; margin-bottom:16px;}
.fp-faq__tab{padding:6px 13px; border:1px solid var(--border-subtle); border-radius:20px; background:var(--bg-secondary); color:var(--text-secondary); font-family:var(--font-mono); font-size:10px; letter-spacing:.06em; transition:var(--transition);}
.fp-faq__tab:hover{border-color:var(--border-accent);}
.fp-faq__tab.is-on{background:var(--accent-primary); color:#0a0a0c; border-color:transparent; font-weight:600;}
.fp-faq__list{display:flex; flex-direction:column; gap:8px;}
.fp-faq__item{border:1px solid var(--border-subtle); border-radius:var(--radius-md); background:var(--bg-secondary); overflow:hidden;}
.fp-faq__item.is-open{border-color:var(--border-accent);}
.fp-faq__q{width:100%; display:flex; align-items:center; justify-content:space-between; gap:12px; padding:14px 16px; background:none; border:none; color:var(--text-primary); font-size:14.5px; font-weight:500; text-align:left;}
.fp-faq__q svg{flex-shrink:0; color:var(--accent-primary); font-size:16px;}
.fp-faq__a{padding:0 16px 15px;}
.fp-faq__cat{font-family:var(--font-mono); font-size:9px; letter-spacing:.12em; color:var(--accent-primary-bright); border:1px solid var(--border-accent); padding:2px 7px; border-radius:12px;}
.fp-faq__a p{margin:9px 0 0; font-size:13.5px; color:var(--text-secondary); line-height:1.6;}
.fp-faq__empty{font-size:13px; color:var(--text-muted); text-align:center; padding:24px;}

/* completion badge */
.fp-badge{margin:30px 0 10px; padding:34px 24px; border-radius:var(--radius-lg); text-align:center; border:1px solid var(--border-subtle); background:var(--bg-secondary);}
.fp-badge.is-on{border-color:var(--accent-primary); background:radial-gradient(120% 100% at 50% 0%, rgba(157,140,245,.16), transparent 65%), var(--bg-secondary); box-shadow:0 0 50px -16px var(--accent-glow); animation:fpBadge .5s ease;}
@keyframes fpBadge{from{opacity:0; transform:scale(.96);} to{opacity:1; transform:scale(1);}}
.fp-badge__seal{width:60px; height:60px; margin:0 auto 16px; border-radius:50%; display:grid; place-items:center; font-size:28px;
  background:linear-gradient(135deg,var(--accent-primary),var(--accent-primary-dim)); color:#0a0a0c; box-shadow:0 0 26px var(--accent-glow);}
.fp-badge__seal--lock{background:var(--bg-tertiary); color:var(--text-muted); box-shadow:none; border:1px solid var(--border-visible);}
.fp-badge__title{font-family:var(--font-heading); font-size:19px; font-weight:700; letter-spacing:.08em;}
.fp-badge.is-on .fp-badge__title{color:var(--accent-primary-bright); text-shadow:0 0 18px var(--accent-glow);}
.fp-badge__sub{font-family:var(--font-mono); font-size:11px; color:var(--text-muted); margin-top:7px; letter-spacing:.06em;}
.fp-badge__awarded{font-family:var(--font-mono); font-size:10px; letter-spacing:.22em; color:var(--text-muted); margin-top:16px;}
.fp-badge__name{font-family:var(--font-heading); font-size:30px; font-weight:700; letter-spacing:.01em; margin-top:6px; color:var(--text-primary);}
.fp-badge.is-on .fp-badge__name{color:var(--accent-primary-bright); text-shadow:0 0 22px var(--accent-glow);}
.fp-badge__line{width:120px; height:1px; margin:14px auto 0; background:linear-gradient(90deg,transparent,var(--accent-primary),transparent);}

/* mark read + footer */
.fp-section__foot{margin-top:22px;}
.fp-markread{background:none; border:1px solid var(--border-visible); color:var(--text-muted); padding:9px 18px; border-radius:8px; font-family:var(--font-mono); font-size:11px; letter-spacing:.1em; display:inline-flex; align-items:center; gap:8px; transition:var(--transition);}
.fp-markread:hover{border-color:var(--border-accent); color:var(--text-secondary);}
.fp-markread.is-done{border-color:var(--accent-green-text); color:var(--accent-green-text); background:rgba(74,222,128,.06);}
.fp-footer{display:flex; align-items:center; gap:10px; justify-content:center; padding:30px 0 0; color:var(--text-muted); font-family:var(--font-mono); font-size:10.5px; letter-spacing:.1em;}

.fp-scrim{display:none;}

/* responsive */
@media (max-width:1000px){ .fp-hydro{grid-template-columns:1fr;} .fp-hydro__cyl{margin-top:6px;} .fp-hydro__tube{height:150px;} }
@media (max-width:860px){
  .fp-burger{display:flex;}
  .fp-sidebar{transform:translateX(-100%); transition:transform .25s ease; box-shadow:0 0 40px rgba(0,0,0,.6);}
  .fp-sidebar.is-open{transform:translateX(0);}
  .fp-content{margin-left:0;}
  .fp-content__inner{padding:24px 20px 100px;}
  .fp-scrim{display:block; position:fixed; inset:var(--header-h) 0 0 0; background:rgba(0,0,0,.5); z-index:25; touch-action:none; overscroll-behavior:contain;}
  .fp-tl,.fp-pc,.fp-upsell-pair,.fp-skin__grid{grid-template-columns:1fr;}
  .fp-skin__grid{grid-template-columns:repeat(2,1fr);}
  .fp-sechead__title{font-size:24px;}
  .fp-header__title{display:none;}
}
@media (prefers-reduced-motion:reduce){ .fp-app *{animation:none !important; transition:none !important; scroll-behavior:auto !important;} }


/* ===== Training-specific components (tp-) ===== */
/* shared primitives */
.tp-tabs{display:flex; gap:6px; flex-wrap:wrap; margin-bottom:16px;}
.tp-tab{font-family:var(--font-mono); font-size:10.5px; letter-spacing:.05em; padding:8px 13px; border:1px solid var(--border-visible); border-radius:30px; background:var(--bg-tertiary); color:var(--text-secondary); cursor:pointer; transition:all var(--transition); white-space:nowrap;}
.tp-tab:hover{border-color:var(--accent-primary); color:var(--text-primary);}
.tp-tab.is-active{border-color:var(--accent-primary); color:var(--accent-primary-bright); background:linear-gradient(180deg,rgba(157,140,245,.2),rgba(157,140,245,.04)); box-shadow:0 0 18px -6px var(--accent-glow);}
.tp-seg{display:flex; border:1px solid var(--border-visible); border-radius:var(--radius-sm); overflow:hidden;}
.tp-seg__b{flex:1; font-family:var(--font-mono); font-size:11px; padding:9px 8px; background:var(--bg-primary); color:var(--text-secondary); border:none; cursor:pointer; transition:all var(--transition); white-space:nowrap;}
.tp-seg__b+.tp-seg__b{border-left:1px solid var(--border-visible);}
.tp-seg__b.is-active{background:linear-gradient(180deg,rgba(157,140,245,.22),rgba(157,140,245,.05)); color:var(--accent-primary-bright);}
.tp-tier{font-family:var(--font-mono); font-size:10px; font-weight:700; width:22px; height:22px; display:inline-flex; align-items:center; justify-content:center; border-radius:5px; flex-shrink:0;}
.tp-tier--S{background:linear-gradient(180deg,var(--accent-primary-bright),var(--accent-primary)); color:var(--bg-primary);}
.tp-tier--A{background:rgba(157,140,245,.22); color:var(--accent-primary-bright); border:1px solid var(--border-accent);}
.tp-tier--B{background:var(--bg-hover); color:var(--text-secondary); border:1px solid var(--border-visible);}
.tp-tier--C{background:transparent; color:var(--text-muted); border:1px solid var(--border-subtle);}

/* HierarchyPyramid (S00) */
.tp-pyr{margin:24px 0; padding:22px 18px; border:1px solid var(--border-accent); border-radius:var(--radius-lg); background:radial-gradient(120% 80% at 50% 0%, rgba(157,140,245,.12), transparent 70%), var(--bg-secondary);}
.tp-pyr__lbl{font-family:var(--font-mono); font-size:10px; letter-spacing:.14em; color:var(--text-muted); text-align:center; margin-bottom:14px;}
.tp-pyr__row{display:flex; align-items:center; gap:10px; margin:0 auto 6px; cursor:pointer; transition:transform var(--transition);}
.tp-pyr__row:hover{transform:translateX(2px);}
.tp-pyr__bar{flex:1; display:flex; align-items:center; gap:10px; padding:10px 14px; border:1px solid var(--border-accent); border-radius:var(--radius-md); background:linear-gradient(180deg,rgba(157,140,245,var(--op,.1)),transparent); transition:all var(--transition);}
.tp-pyr__row:hover .tp-pyr__bar{border-color:var(--accent-primary-bright); box-shadow:0 0 20px -8px var(--accent-glow);}
.tp-pyr__rank{font-family:var(--font-mono); font-size:13px; font-weight:700; color:var(--accent-primary-bright); width:18px; text-align:center;}
.tp-pyr__name{font-family:var(--font-heading); font-size:13px; font-weight:600; color:var(--text-primary); letter-spacing:.02em;}
.tp-pyr__hint{margin-left:auto; font-family:var(--font-mono); font-size:8.5px; color:var(--text-muted); opacity:0; transition:opacity var(--transition);}
.tp-pyr__row:hover .tp-pyr__hint{opacity:1;}
.tp-pyr__note{margin-top:12px; padding:11px 14px; border-radius:var(--radius-md); border:1px dashed var(--border-accent); background:var(--bg-primary); font-size:12.5px; color:var(--text-secondary); line-height:1.5; text-align:center; min-height:20px;}
/* sidebar mini pyramid */
.tp-pyrmini{display:flex; flex-direction:column; align-items:center; gap:3px; padding:10px 8px;}
.tp-pyrmini__bar{height:7px; border-radius:2px; background:var(--accent-primary-dim); transition:all var(--transition);}
.tp-pyrmini__bar.is-on{background:var(--accent-primary-bright); box-shadow:0 0 10px -2px var(--accent-glow);}
.tp-pyrmini__lbl{font-family:var(--font-mono); font-size:8.5px; letter-spacing:.1em; color:var(--text-muted); margin-top:6px;}

/* OnboardingQuiz (S00) + sidebar status */
.tp-quiz{margin:24px 0; padding:22px; border:1px solid var(--border-accent); border-radius:var(--radius-lg); background:var(--bg-secondary);}
.tp-quiz__lbl{font-family:var(--font-mono); font-size:10px; letter-spacing:.14em; color:var(--text-muted); margin-bottom:16px;}
.tp-quiz__q{margin-bottom:18px;}
.tp-quiz__qt{font-family:var(--font-heading); font-size:14px; font-weight:600; color:var(--text-primary); margin-bottom:9px;}
.tp-quiz__opts{display:flex; gap:8px; flex-wrap:wrap;}
.tp-quiz__opt{font-family:var(--font-mono); font-size:11px; padding:9px 14px; border:1px solid var(--border-visible); border-radius:var(--radius-md); background:var(--bg-tertiary); color:var(--text-secondary); cursor:pointer; transition:all var(--transition);}
.tp-quiz__opt:hover{border-color:var(--accent-primary);}
.tp-quiz__opt.is-active{border-color:var(--accent-primary); color:var(--accent-primary-bright); background:linear-gradient(180deg,rgba(157,140,245,.2),rgba(157,140,245,.04)); box-shadow:0 0 16px -6px var(--accent-glow);}
.tp-quiz__result{margin-top:8px; padding:18px; border-radius:var(--radius-md); border:1px solid var(--accent-primary-dim); background:radial-gradient(120% 90% at 50% 0%, rgba(157,140,245,.12), transparent 70%), var(--bg-primary); animation:tpfade .3s ease;}
@keyframes tpfade{from{opacity:0;transform:translateY(6px);}to{opacity:1;transform:translateY(0);}}
.tp-quiz__rh{font-family:var(--font-mono); font-size:9.5px; letter-spacing:.12em; color:var(--accent-primary-bright); margin-bottom:10px;}
.tp-quiz__rrow{display:flex; justify-content:space-between; gap:10px; padding:8px 0; border-bottom:1px solid var(--border-subtle); font-size:13px;}
.tp-quiz__rrow:last-child{border-bottom:none;}
.tp-quiz__rk{color:var(--text-muted); font-family:var(--font-mono); font-size:11px;}
.tp-quiz__rv{color:var(--accent-primary-bright); font-weight:600; text-align:right;}
.tp-quiz__reset{margin-top:12px; font-family:var(--font-mono); font-size:10px; padding:8px 14px; border:1px solid var(--border-visible); border-radius:30px; background:transparent; color:var(--text-muted); cursor:pointer;}
.tp-quiz__reset:hover{border-color:var(--accent-red-text); color:var(--accent-red-text);}
.tp-status{padding:12px 13px; border:1px solid var(--border-subtle); border-radius:var(--radius-md); background:var(--bg-tertiary);}
.tp-status__lbl{font-family:var(--font-mono); font-size:8.5px; letter-spacing:.1em; color:var(--text-muted); margin-bottom:8px;}
.tp-status__badges{display:flex; flex-wrap:wrap; gap:5px;}
.tp-status__b{font-family:var(--font-mono); font-size:9px; padding:3px 8px; border-radius:12px; background:rgba(157,140,245,.12); color:var(--accent-primary-bright); border:1px solid var(--border-accent);}
.tp-status__match{margin-top:9px; padding-top:9px; border-top:1px solid var(--border-subtle); font-size:11px; color:var(--text-secondary); line-height:1.4;}
.tp-status__match b{color:var(--accent-primary-bright);}
.tp-status__cta{font-family:var(--font-mono); font-size:9.5px; letter-spacing:.06em; color:var(--accent-primary-bright);}

/* ThreeMechanisms (S01) */
.tp-mech{display:grid; grid-template-columns:1fr 1fr 1fr; gap:11px; margin:24px 0;}
@media (max-width:640px){.tp-mech{grid-template-columns:1fr;}}
.tp-mech__card{border:1px solid var(--border-visible); border-radius:var(--radius-lg); background:var(--bg-secondary); padding:18px 16px; cursor:pointer; transition:all var(--transition);}
.tp-mech__card[data-rank="1"]{border-color:var(--accent-primary); background:radial-gradient(120% 80% at 50% 0%,rgba(157,140,245,.16),transparent 70%),var(--bg-secondary); box-shadow:0 0 30px -12px var(--accent-glow);}
.tp-mech__card[data-rank="2"]{background:radial-gradient(120% 80% at 50% 0%,rgba(157,140,245,.07),transparent 70%),var(--bg-secondary);}
.tp-mech__card:hover{border-color:var(--accent-primary-bright);}
.tp-mech__n{font-family:var(--font-mono); font-size:11px; color:var(--text-muted);}
.tp-mech__badge{display:inline-block; font-family:var(--font-mono); font-size:8px; letter-spacing:.08em; padding:3px 8px; border-radius:12px; margin:8px 0; text-transform:uppercase;}
.tp-mech__card[data-rank="1"] .tp-mech__badge{background:linear-gradient(180deg,var(--accent-primary-bright),var(--accent-primary)); color:var(--bg-primary);}
.tp-mech__card[data-rank="2"] .tp-mech__badge{background:rgba(157,140,245,.18); color:var(--accent-primary-bright); border:1px solid var(--border-accent);}
.tp-mech__card[data-rank="3"] .tp-mech__badge{background:var(--bg-hover); color:var(--text-muted); border:1px solid var(--border-subtle);}
.tp-mech__name{font-family:var(--font-heading); font-size:15px; font-weight:600; color:var(--text-primary); margin-bottom:8px;}
.tp-mech__body{font-size:12.5px; color:var(--text-secondary); line-height:1.55;}
.tp-mech__more{margin-top:10px; font-family:var(--font-mono); font-size:8.5px; color:var(--text-muted);}

/* MythBuster (S01) */
.tp-myth{border-left:3px solid var(--accent-red-text); border-radius:0 var(--radius-md) var(--radius-md) 0; background:var(--bg-secondary); padding:14px 16px; margin-bottom:10px;}
.tp-myth__m{display:flex; gap:9px; align-items:baseline; margin-bottom:8px;}
.tp-myth__tag{font-family:var(--font-mono); font-size:9px; letter-spacing:.1em; color:var(--accent-red-text); border:1px solid rgba(248,113,113,.4); border-radius:10px; padding:2px 8px; flex-shrink:0;}
.tp-myth__mt{font-size:13.5px; color:var(--text-primary); font-style:italic;}
.tp-myth__r{display:flex; gap:9px; align-items:baseline;}
.tp-myth__rtag{font-family:var(--font-mono); font-size:9px; letter-spacing:.1em; color:var(--accent-green-text); border:1px solid rgba(74,222,128,.4); border-radius:10px; padding:2px 8px; flex-shrink:0;}
.tp-myth__rt{font-size:13px; color:var(--text-secondary); line-height:1.5;}

/* EffectiveRepVisual (S02) */
.tp-spec{margin:24px 0; padding:24px 22px; border:1px solid var(--border-accent); border-radius:var(--radius-lg); background:radial-gradient(120% 90% at 50% 0%, rgba(157,140,245,.1), transparent 70%), var(--bg-secondary);}
.tp-spec__lbl{font-family:var(--font-mono); font-size:10px; letter-spacing:.14em; color:var(--text-muted); margin-bottom:18px;}
.tp-spec__track{position:relative; height:46px; border-radius:24px; background:linear-gradient(90deg, var(--bg-hover) 0%, var(--accent-primary-dim) 30%, var(--accent-primary) 55%, var(--accent-primary-bright) 80%, var(--accent-red-text) 100%); border:1px solid var(--border-visible); cursor:pointer;}
.tp-spec__zones{position:absolute; inset:0; display:flex; pointer-events:none;}
.tp-spec__zone{display:flex; align-items:center; justify-content:center; font-family:var(--font-mono); font-size:9px; letter-spacing:.06em; color:rgba(255,255,255,.85); border-right:1px dashed rgba(255,255,255,.18);}
.tp-spec__zone:last-child{border-right:none;}
.tp-spec__ind{position:absolute; top:-6px; width:4px; height:58px; background:#fff; border-radius:3px; box-shadow:0 0 12px 2px var(--accent-glow); transform:translateX(-50%); transition:left .08s linear;}
.tp-spec__scale{display:flex; justify-content:space-between; font-family:var(--font-mono); font-size:9px; color:var(--text-muted); margin-top:8px;}
.tp-spec__read{margin-top:16px; padding:14px 16px; border-radius:var(--radius-md); border:1px solid var(--border-accent); background:var(--bg-primary); text-align:center;}
.tp-spec__rv{font-family:var(--font-mono); font-size:13px; color:var(--accent-primary-bright); font-weight:700; margin-bottom:4px;}
.tp-spec__rt{font-size:13px; color:var(--text-secondary); line-height:1.5;}

/* VolumeTracker (S02) */
.tp-vt{margin:24px 0; padding:22px; border:1px solid var(--border-accent); border-radius:var(--radius-lg); background:var(--bg-secondary);}
.tp-vt__lbl{font-family:var(--font-mono); font-size:10px; letter-spacing:.14em; color:var(--text-muted); margin-bottom:14px;}
.tp-vt__age{display:flex; gap:8px; margin-bottom:16px; flex-wrap:wrap;}
.tp-vt__grid{overflow-x:auto;}
.tp-vt__table{border-collapse:separate; border-spacing:5px; min-width:480px;}
.tp-vt__mh{font-family:var(--font-heading); font-size:11px; font-weight:600; color:var(--text-secondary); text-align:left; padding-right:10px; white-space:nowrap;}
.tp-vt__dh{font-family:var(--font-mono); font-size:10px; color:var(--text-muted); width:30px; text-align:center;}
.tp-vt__cell{width:30px; height:26px; border-radius:5px; border:1px solid var(--border-subtle); background:var(--bg-primary); cursor:pointer; transition:all var(--transition); padding:0;}
.tp-vt__cell:hover{border-color:var(--accent-primary);}
.tp-vt__cell.is-on{background:linear-gradient(180deg,var(--accent-primary),var(--accent-primary-dim)); border-color:var(--accent-primary-bright); box-shadow:0 0 10px -2px var(--accent-glow);}
.tp-vt__stat{font-family:var(--font-mono); font-size:10px; min-width:96px; padding-left:8px; white-space:nowrap;}
.tp-vt__bar{height:5px; border-radius:3px; background:var(--bg-hover); margin-top:4px; overflow:hidden;}
.tp-vt__fill{height:100%; transition:width .3s ease;}
.tp-vt__fill--low{background:var(--text-muted);}
.tp-vt__fill--mav{background:var(--accent-primary-bright);}
.tp-vt__fill--warn{background:var(--accent-warn-bright);}
.tp-vt__fill--over{background:var(--accent-red-text);}
.tp-vt__zone{font-size:9px;}
.tp-vt__row-foot{display:flex; gap:10px; align-items:center; margin-top:16px;}
.tp-vt__save{font-family:var(--font-mono); font-size:10px; padding:8px 15px; border:1px solid var(--accent-primary); border-radius:30px; background:linear-gradient(180deg,rgba(157,140,245,.2),rgba(157,140,245,.04)); color:var(--accent-primary-bright); cursor:pointer;}
.tp-vt__reset{font-family:var(--font-mono); font-size:10px; padding:8px 13px; border:1px solid var(--border-visible); border-radius:30px; background:transparent; color:var(--text-muted); cursor:pointer;}

/* MuscleGroupGuide (S04) */
.tp-mg__panel{border:1px solid var(--border-accent); border-radius:var(--radius-lg); background:var(--bg-secondary); padding:20px;}
.tp-mg__name{font-family:var(--font-heading); font-size:20px; font-weight:700; color:var(--accent-primary-bright); margin-bottom:14px;}

/* ExerciseScorer (S05) */
.tp-sc{margin:24px 0; padding:22px; border:1px solid var(--border-accent); border-radius:var(--radius-lg); background:var(--bg-secondary);}
.tp-sc__lbl{font-family:var(--font-mono); font-size:10px; letter-spacing:.14em; color:var(--text-muted); margin-bottom:16px;}
.tp-sc__name{width:100%; background:var(--bg-primary); border:1px solid var(--border-visible); border-radius:var(--radius-sm); color:var(--text-primary); font-family:var(--font-mono); font-size:13px; padding:9px 12px; margin-bottom:18px;}
.tp-sc__name:focus{outline:none; border-color:var(--accent-primary);}
.tp-sc__slider{margin-bottom:15px;}
.tp-sc__sh{display:flex; justify-content:space-between; margin-bottom:6px; font-size:12px;}
.tp-sc__sk{color:var(--text-secondary);}
.tp-sc__sv{font-family:var(--font-mono); color:var(--accent-primary-bright); font-weight:700;}
.tp-sc input[type=range]{width:100%; accent-color:var(--accent-primary);}
.tp-sc__out{margin-top:18px; padding:16px; border-radius:var(--radius-md); border:1px solid var(--accent-primary-dim); background:var(--bg-primary); display:flex; align-items:center; justify-content:center; gap:16px;}
.tp-sc__total{font-family:var(--font-mono); font-size:30px; font-weight:700; color:var(--accent-primary-bright); text-shadow:0 0 20px var(--accent-glow);}
.tp-sc__tunit{font-family:var(--font-mono); font-size:11px; color:var(--text-muted);}
.tp-sc__presets{display:flex; gap:8px; margin-top:14px; flex-wrap:wrap;}
.tp-sc__preset{font-family:var(--font-mono); font-size:10px; padding:7px 12px; border:1px solid var(--border-visible); border-radius:30px; background:var(--bg-tertiary); color:var(--text-secondary); cursor:pointer;}
.tp-sc__preset:hover{border-color:var(--accent-primary); color:var(--accent-primary-bright);}

/* RIRGauge (S07) */
.tp-rir{margin:24px 0; padding:22px; border:1px solid var(--border-accent); border-radius:var(--radius-lg); background:var(--bg-secondary); display:flex; gap:22px; flex-wrap:wrap;}
.tp-rir__col{display:flex; flex-direction:column; gap:4px; min-width:60px;}
.tp-rir__band{position:relative; padding:8px 12px; border-radius:6px; border:1px solid var(--border-subtle); background:var(--bg-primary); cursor:pointer; font-family:var(--font-mono); font-size:11px; color:var(--text-secondary); transition:all var(--transition); text-align:center;}
.tp-rir__band:hover{border-color:var(--accent-primary);}
.tp-rir__band.is-active{border-color:var(--accent-primary-bright); color:var(--accent-primary-bright);}
.tp-rir__band.in-zone{background:linear-gradient(90deg,rgba(157,140,245,.18),transparent); border-color:var(--accent-primary);}
.tp-rir__zone{font-family:var(--font-mono); font-size:8.5px; letter-spacing:.08em; color:var(--accent-primary-bright); margin-top:8px; text-align:center;}
.tp-rir__detail{flex:1; min-width:200px; padding:16px; border-radius:var(--radius-md); border:1px dashed var(--border-accent); background:var(--bg-primary);}
.tp-rir__dh{font-family:var(--font-mono); font-size:13px; color:var(--accent-primary-bright); font-weight:700; margin-bottom:8px;}
.tp-rir__dt{font-size:13px; color:var(--text-secondary); line-height:1.55;}

/* SplitComparison (S09) */
.tp-spl{display:grid; grid-template-columns:1fr 1fr; gap:11px; margin:22px 0;}
@media (max-width:640px){.tp-spl{grid-template-columns:1fr;}}
.tp-spl__card{border:1px solid var(--border-visible); border-radius:var(--radius-lg); background:var(--bg-secondary); padding:16px 18px; cursor:pointer; transition:all var(--transition);}
.tp-spl__card:hover{border-color:var(--accent-primary);}
.tp-spl__card.is-rec{border-color:var(--accent-primary); box-shadow:0 0 22px -10px var(--accent-glow);}
.tp-spl__name{font-family:var(--font-heading); font-size:15px; font-weight:600; color:var(--text-primary);}
.tp-spl__rec{font-family:var(--font-mono); font-size:8px; letter-spacing:.08em; color:var(--accent-primary-bright); border:1px solid var(--border-accent); border-radius:10px; padding:2px 7px; margin-left:8px;}
.tp-spl__meta{display:flex; gap:8px; margin:10px 0; flex-wrap:wrap;}
.tp-spl__chip{font-family:var(--font-mono); font-size:9px; padding:3px 8px; border-radius:12px; background:var(--bg-tertiary); color:var(--text-secondary); border:1px solid var(--border-subtle);}
.tp-spl__for{font-size:12.5px; color:var(--text-secondary); line-height:1.5;}

/* ProgressionTracker (S10) */
.tp-prog{margin:24px 0;}
.tp-prog__nodes{display:flex; gap:10px; margin-bottom:14px;}
.tp-prog__node{flex:1; padding:14px 12px; border:1px solid var(--border-visible); border-radius:var(--radius-md); background:var(--bg-tertiary); cursor:pointer; text-align:center; transition:all var(--transition);}
.tp-prog__node:hover{border-color:var(--accent-primary);}
.tp-prog__node.is-active{border-color:var(--accent-primary); background:linear-gradient(180deg,rgba(157,140,245,.16),transparent); box-shadow:0 0 22px -10px var(--accent-glow);}
.tp-prog__nn{font-family:var(--font-mono); font-size:18px; font-weight:700; color:var(--accent-primary-bright);}
.tp-prog__nl{font-family:var(--font-heading); font-size:12px; font-weight:600; color:var(--text-primary); margin-top:4px;}
.tp-prog__nm{font-family:var(--font-mono); font-size:8.5px; color:var(--text-muted); margin-top:2px;}
.tp-prog__panel{padding:18px; border:1px solid var(--accent-primary-dim); border-radius:var(--radius-lg); background:var(--bg-secondary); animation:tpfade .3s ease;}

/* MesocyclePlanner (S11) */
.tp-meso{margin:24px 0; padding:22px; border:1px solid var(--border-accent); border-radius:var(--radius-lg); background:var(--bg-secondary);}
.tp-meso__lbl{font-family:var(--font-mono); font-size:10px; letter-spacing:.14em; color:var(--text-muted); margin-bottom:16px;}
.tp-meso__ctrls{display:flex; gap:12px; flex-wrap:wrap; margin-bottom:18px;}
.tp-meso__field{display:flex; flex-direction:column; gap:6px;}
.tp-meso__fl{font-family:var(--font-mono); font-size:9px; letter-spacing:.08em; color:var(--text-muted); text-transform:uppercase;}
.tp-meso__week{display:flex; align-items:center; gap:12px; padding:11px 14px; border:1px solid var(--border-subtle); border-radius:var(--radius-md); background:var(--bg-primary); margin-bottom:7px;}
.tp-meso__wk{font-family:var(--font-mono); font-size:11px; color:var(--accent-primary-bright); font-weight:700; width:54px;}
.tp-meso__wfocus{font-family:var(--font-heading); font-size:12.5px; font-weight:600; color:var(--text-primary); flex:1;}
.tp-meso__wmeta{font-family:var(--font-mono); font-size:9.5px; color:var(--text-muted); text-align:right;}
.tp-meso__chk{width:18px; height:18px; border-radius:5px; border:1px solid var(--border-visible); background:var(--bg-tertiary); cursor:pointer; display:flex; align-items:center; justify-content:center; color:var(--accent-primary-bright); flex-shrink:0;}
.tp-meso__chk.is-on{background:linear-gradient(180deg,rgba(157,140,245,.3),rgba(157,140,245,.08)); border-color:var(--accent-primary);}
.tp-meso__week.is-deload{border-color:var(--accent-warn); background:rgba(201,168,76,.06);}
.tp-meso__week.is-deload .tp-meso__wk{color:var(--accent-warn-bright);}

/* PlateauDiagnostic (S14) */
.tp-plat{margin:22px 0; padding:20px; border:1px solid var(--border-accent); border-radius:var(--radius-lg); background:var(--bg-secondary);}
.tp-plat__step{display:flex; gap:13px; padding:12px 0; border-bottom:1px solid var(--border-subtle);}
.tp-plat__step:last-child{border-bottom:none;}
.tp-plat__n{font-family:var(--font-mono); font-size:11px; font-weight:700; color:var(--accent-primary-bright); width:26px; height:26px; flex-shrink:0; display:flex; align-items:center; justify-content:center; border:1px solid var(--border-accent); border-radius:50%;}
.tp-plat__t{font-size:13.5px; color:var(--text-secondary); line-height:1.55;}

/* ProgramSelector (S18) */
.tp-ps__card{border:1px solid var(--border-visible); border-radius:var(--radius-lg); background:var(--bg-secondary); margin-bottom:11px; overflow:hidden; transition:border var(--transition);}
.tp-ps__card.is-rec{border-color:var(--accent-primary); box-shadow:0 0 22px -12px var(--accent-glow);}
.tp-ps__head{display:flex; align-items:center; gap:10px; padding:15px 18px; cursor:pointer;}
.tp-ps__name{font-family:var(--font-heading); font-size:14px; font-weight:600; color:var(--text-primary); flex:1;}
.tp-ps__rec{font-family:var(--font-mono); font-size:8px; letter-spacing:.06em; color:var(--accent-primary-bright); border:1px solid var(--border-accent); border-radius:10px; padding:3px 8px;}
.tp-ps__body{padding:0 18px 18px; border-top:1px solid var(--border-subtle);}

/* PersonalSplitsToggle (S19) */
.tp-pst__active{margin-top:14px; display:flex; gap:10px; align-items:center; flex-wrap:wrap;}
.tp-pst__set{font-family:var(--font-mono); font-size:10.5px; letter-spacing:.06em; padding:10px 18px; border:1px solid var(--accent-primary); border-radius:30px; background:linear-gradient(180deg,rgba(157,140,245,.2),rgba(157,140,245,.04)); color:var(--accent-primary-bright); cursor:pointer;}
.tp-pst__set.is-set{background:var(--accent-primary); color:var(--bg-primary);}
.tp-pst__note{font-size:12px; color:var(--text-muted); line-height:1.5; margin-top:10px; padding:11px 14px; border-left:2px solid var(--accent-warn); background:rgba(201,168,76,.05); border-radius:0 var(--radius-sm) var(--radius-sm) 0;}

/* CheatSheetPanel (S21) */
.tp-cheat__item{border:1px solid var(--border-visible); border-radius:var(--radius-md); background:var(--bg-secondary); margin-bottom:8px; overflow:hidden;}
.tp-cheat__head{display:flex; align-items:center; justify-content:space-between; padding:13px 16px; cursor:pointer; font-family:var(--font-heading); font-size:13px; font-weight:600; color:var(--text-primary);}
.tp-cheat__body{padding:0 16px 14px; border-top:1px solid var(--border-subtle);}
.tp-cheat__copy{font-family:var(--font-mono); font-size:10px; letter-spacing:.06em; padding:9px 16px; border:1px solid var(--accent-primary); border-radius:30px; background:linear-gradient(180deg,rgba(157,140,245,.2),rgba(157,140,245,.04)); color:var(--accent-primary-bright); cursor:pointer; margin-bottom:14px;}
.tp-check{display:flex; align-items:flex-start; gap:10px; padding:8px 0; cursor:pointer;}
.tp-check__box{width:18px; height:18px; border-radius:5px; border:1px solid var(--border-visible); background:var(--bg-tertiary); flex-shrink:0; display:flex; align-items:center; justify-content:center; color:var(--accent-primary-bright); margin-top:1px;}
.tp-check__box.is-on{background:linear-gradient(180deg,rgba(157,140,245,.3),rgba(157,140,245,.08)); border-color:var(--accent-primary);}
.tp-check__t{font-size:13px; color:var(--text-secondary); line-height:1.5;}
.tp-check.is-done .tp-check__t{color:var(--text-muted); text-decoration:line-through;}

/* session flow (S08) */
.tp-flow{display:flex; align-items:center; gap:8px; flex-wrap:wrap; margin:20px 0;}
.tp-flow__step{flex:1; min-width:120px; padding:14px; border:1px solid var(--border-accent); border-radius:var(--radius-md); background:radial-gradient(120% 80% at 50% 0%,rgba(157,140,245,.1),transparent),var(--bg-secondary); text-align:center;}
.tp-flow__sn{font-family:var(--font-mono); font-size:9px; color:var(--text-muted);}
.tp-flow__st{font-family:var(--font-heading); font-size:13px; font-weight:600; color:var(--text-primary); margin-top:4px;}
.tp-flow__arrow{color:var(--accent-primary); font-size:18px; flex-shrink:0;}

/* 1-1 coaching cross-sell */
.tp-coach{position:relative; margin-top:14px; padding:26px 24px; border:1px solid var(--accent-primary-dim); border-radius:var(--radius-lg); background:radial-gradient(140% 120% at 50% 0%, rgba(157,140,245,.14), transparent 65%), var(--bg-primary); text-align:center; overflow:hidden;}
.tp-coach__tag{display:inline-flex; align-items:center; gap:7px; font-family:var(--font-mono); font-size:9px; letter-spacing:.16em; color:var(--accent-primary-bright); border:1px solid var(--border-accent); border-radius:30px; padding:5px 13px; margin-bottom:15px;}
.tp-coach__name{font-family:var(--font-heading); font-size:21px; font-weight:700; color:var(--text-primary); margin:0 0 10px;}
.tp-coach__desc{font-size:14px; color:var(--text-secondary); line-height:1.6; max-width:520px; margin:0 auto 20px;}
.tp-coach__cta{display:inline-flex; align-items:center; gap:9px; font-family:var(--font-mono); font-size:11.5px; letter-spacing:.1em; color:var(--bg-primary); background:linear-gradient(180deg,var(--accent-primary-bright),var(--accent-primary)); padding:13px 26px; border-radius:30px; box-shadow:0 0 30px -8px var(--accent-glow);}
.tp-xsell-lbl{font-family:var(--font-mono); font-size:10px; letter-spacing:.14em; color:var(--text-muted); text-align:center; margin:30px 0 4px;}
.tp-icrow{display:flex; gap:10px; flex-wrap:wrap; margin:16px 0;}
.tp-ic{display:flex; align-items:center; gap:8px; padding:9px 14px; border:1px solid var(--border-subtle); border-radius:30px; background:var(--bg-secondary); font-size:12.5px; color:var(--text-secondary);}
.tp-ic__i{color:var(--accent-primary-bright); display:flex; font-size:15px;}
`}</style>; }
